def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about food into a single fluent sentence."""
    if not triples:
        return ""

    phrases = []
    for t in triples:
        # Accept both Triple objects and plain (subject, predicate, object) tuples
        if isinstance(t, Triple):
            s, p, o = t.subject, t.predicate, t.object
        else:
            s, p, o = t
        # Predicate‑specific phrasing – keep clauses short so they can be turned into
        # relative clauses later without repeating the subject.
        if p == "country":
            phrase = f"is from {o}"
        elif p == "ingredient":
            phrase = f"contains {o}"
        elif p == "region":
            phrase = f"is from the {o} region"
        elif p == "division":
            phrase = f"belongs to the {o} division"
        elif p == "family":
            phrase = f"is in the {o} family"
        elif p == "order":
            phrase = f"belongs to the {o} order"
        elif p == "course":
            phrase = f"is served as a {o}"
        elif p == "mainIngredient":
            phrase = f"has main ingredients {o}"
        elif p == "dishVariation":
            phrase = f"can be varied with {o}"
        elif p == "leader":
            phrase = f"has leader {o}"
        elif p == "alternativeName":
            phrase = f"is also known as {o}"
        elif p in ("creatorOfDish", "creator"):
            phrase = f"was created by {o}"
        elif p in ("servingTemperature", "served"):
            phrase = f"is served {o}"
        elif p == "carbohydrate":
            phrase = f"contains {o} carbohydrates"
        elif p == "fat":
            phrase = f"contains {o} fat"
        elif p == "protein":
            phrase = f"contains {o} protein"
        elif p == "year":
            phrase = f"was introduced in {o}"
        elif p == "related":
            phrase = f"is related to {o}"
        elif p == "similarDish":
            phrase = f"is similar to {o}"
        elif p == "genus":
            phrase = f"belongs to the genus {o}"
        elif p == "language":
            phrase = f"has language {o}"
        elif p == "isPartOf":
            phrase = f"is part of {o}"
        elif p == "currency":
            phrase = f"uses currency {o}"
        elif p == "demonym":
            phrase = f"has demonym {o}"
        elif p == "capital":
            phrase = f"has capital {o}"
        elif p == "ethnicGroup":
            phrase = f"has ethnic group {o}"
        elif p == "foundationPlace":
            phrase = f"was founded in {o}"
        elif p == "officialLanguage":
            phrase = f"has official language {o}"
        elif p == "leaderTitle":
            phrase = f"has leader title {o}"
        elif p == "servingSize":
            phrase = f"has serving size {o}"
        elif p == "class":
            phrase = f"belongs to the class {o}"
        else:
            phrase = f"{p} {o}"
        phrases.append(phrase)

    # Combine all phrases into a single fluent sentence.
    # Group phrases by their subject and join them with commas;
    # separate different subjects with "and".
    from collections import defaultdict

    subject_phrases = defaultdict(list)
    for t, phrase in zip(triples, phrases):
        subject_phrases[t.subject].append(phrase)

    clause_texts = []
    for subj, phs in subject_phrases.items():
        if not phs:
            continue
        # Keep the first phrase as is.
        base = phs[0]
        # Transform subsequent phrases into relative clauses using "which".
        others = []
        for p in phs[1:]:
            phrase = p
            # Remove leading subject if present.
            if phrase.lower().startswith(subj.lower()):
                phrase = phrase[len(subj):].lstrip()
            # Lower‑case the first character.
            if phrase:
                phrase = phrase[0].lower() + phrase[1:]
            # Prefix with a relative connector.
            others.append(f"which {phrase}")
        clause = base if not others else f"{base}, " + ", ".join(others)
        clause_texts.append(clause)

    sentence = " and ".join(clause_texts)
    if not sentence.endswith("."):
        sentence += "."
    return sentence

